#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int is_periodic(int n) {
    int len = 0;
    int prev = -1;
    int curr_len = 0;
    while (n > 0) {
        int curr = n % 2;
        if (curr != prev) {
            if (prev != -1 && curr_len != len) {
                return 0;
            }
            len = curr_len;
            curr_len = 1;
        } else {
            curr_len++;
        }
        prev = curr;
        n /= 2;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        int count = 0;
        for (int i = L; i <= R; i++) {
            if (is_periodic(i)) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

