import java.util.Scanner;

public class Main {
    public static boolean is_periodic(int n) {
        int len = 0;
        int prev = -1;
        int curr_len = 0;
        while (n > 0) {
            int curr = n % 2;
            if (curr != prev) {
                if (prev != -1 && curr_len != len) {
                    return false;
                }
                len = curr_len;
                curr_len = 1;
            } else {
                curr_len++;
            }
            prev = curr;
            n /= 2;
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int count = 0;
            for (int i = L; i <= R; i++) {
                if (is_periodic(i)) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

